local QBCore = exports['qb-core']:GetCoreObject()\n\n-- Inventory Variables\nlocal PlayerData = {}\nlocal PlayerInventory = {}\nlocal WeightLimit = 120 -- 120kg weight limit\n\n-- Inventory UI Variables\nlocal InventoryOpen = false\nlocal GridSize = 5 -- Size of empty grid layout\nlocal ThemeColor = {r = 255, g = 69, b = 0} -- Red/Orange theme\n\n-- Function to open the inventory\nfunction OpenInventory()\n    if not InventoryOpen then\n        SetNuiFocus(true, true)\n        SendNUIMessage({action = 'open', inventory = PlayerInventory, weightLimit = WeightLimit, gridSize = GridSize, themeColor = ThemeColor})\n        InventoryOpen = true\n    end\nend\n\n-- Function to close the inventory\nfunction CloseInventory()\n    SetNuiFocus(false, false)\n    SendNUIMessage({action = 'close'})\n    InventoryOpen = false\nend\n\n-- Event to toggle the inventory\nRegisterNUICallback('toggleInventory', function()\n    if InventoryOpen then\n        CloseInventory()\n    else\n        OpenInventory()\n    end\nend)\n\n-- Event to set player data\nRegisterNetEvent('QBCore:Client:OnPlayerLoaded', function()\n    PlayerData = QBCore.Functions.GetPlayerData()\n    PlayerInventory = PlayerData.items\nend)\n\n-- Cleanup TriggerEvents to prevent memory leaks\nAddEventHandler('onResourceStop', function(resource)\n    if resource == GetCurrentResourceName() then\n        -- Clean up any active events and UI messages\n        TriggerEvent('QBCore:Client:OnPlayerLoaded')\n        CloseInventory()\n    end\nend)\n\n-- Initialization\nCitizen.CreateThread(function()\n    while true do\n        Citizen.Wait(100)\n        if IsControlJustReleased(0, 58) then -- Change 58 to your desired input for opening inventory\n            OpenInventory()\n        end\n    end\nend)\n